import { PropsIconsNameCore } from '@semparar/design-system-app';

export interface ParameterPointsProgramValue {
  questions: Array<{
    question: string;
    answer: string;
  }>;
  order: number;
  icon: PropsIconsNameCore;
}

export interface ParameterPointsProgramResponse {
  dateCreated: string;
  status: number;
  category: string;
  PK: string;
  dateUpdated: string;
  value: string | ParameterPointsProgramValue;
}

export enum ParameterPointsProgramStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface ParameterPointsProgramState {
  data?: ParameterPointsProgramResponse[];
  selectedCategory?: ParameterPointsProgramResponse;
  status: ParameterPointsProgramStatus;
  pointsQuantity: number;
  conversionFactor: number;
}

import { Box, Button, ListTextIcon, Text } from '@semparar/design-system-app';
import React, { FC } from 'react';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { Skeleton } from '../../components/TransactionsListFactory/styles';
import { InvoiceCashbackViewProps } from './models';

const InvoiceCashbackView: FC<InvoiceCashbackViewProps> = ({
  items,
  hasError,
  hasLoading,
  handleGoBack,
  handleContinue,
  handleRetry,
  cashbackInvoiceList,
  isLoadingParameterization,
  width,
}) => {
  return (
    <BasicScreen
      hasScroll
      hasHeader
      bgColor="BRAND_COMPLEMENT_03"
      leftIconOnPress={handleGoBack}
      title="Cashback na fatura"
      hasRightIcon={false}
      errorButtonOnPress={handleRetry}
      isLoading={hasLoading}
      hasError={hasError}
    >
      <Box ml="smaller" mr="smaller">
        <Text
          color="INTENSE_COLOR_05"
          testID="invoice-cashback-main-title"
          type="headingMDL"
          mt="smaller"
        >
          Use pontos para pagar menos na fatura
        </Text>
      </Box>
      {isLoadingParameterization &&
        cashbackInvoiceList?.map?.((_, index) => (
          <Box pd="innerLarge" key={`skeleton-${index}`}>
            <Skeleton width={width - 40} height={60} />
          </Box>
        ))}
      {!isLoadingParameterization && (
        <>
          <Box ml="nano" mr="nano" flex={1} justify="flex-start">
            <ListTextIcon
              items={items}
              ml="nano"
              mr="xs"
              mt="xxs"
              type="list"
            />
          </Box>

          <Box ml="smaller" mr="smaller">
            <Button
              text="Continuar"
              mt="large"
              mb="small"
              onPress={handleContinue}
              testID="invoice-cashback-button"
            />
          </Box>
        </>
      )}
    </BasicScreen>
  );
};

export default InvoiceCashbackView;

